import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist", "alpha": 2.0}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    if 'outdoor' in pstr: return 'outdoor'
    return 'room'

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in neighs if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def get_edge_distance(a, b):
        return ((a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2) ** 0.5

    def shortest_path_distance(start, goal):
        if start == goal:
            return 0.0
        pq = [(0.0, start)]
        dists = {start: 0.0}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                return d
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    heapq.heappush(pq, (new_d, neigh))
        return float('inf')

    def find_next_on_path(start, goal):
        if start == goal:
            return start
        pq = [(0.0, start)]
        dists = {start: 0.0}
        prev = {start: None}
        while pq:
            d, curr = heapq.heappop(pq)
            if d > dists.get(curr, float('inf')):
                continue
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                edge_d = get_edge_distance(curr, neigh)
                new_d = d + edge_d
                if new_d < dists.get(neigh, float('inf')):
                    dists[neigh] = new_d
                    prev[neigh] = curr
                    heapq.heappush(pq, (new_d, neigh))
        if goal not in prev:
            return None
        curr = goal
        while prev.get(curr) != start and prev.get(curr) is not None:
            curr = prev[curr]
        return curr

    alpha = model.get("alpha", 2.0)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = shortest_path_distance(current_pos, tcoord)
        if dist == float('inf') or dist <= 0.0:
            continue
        score = util / (dist ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    eval_config_path = data_path / "eval_config.json"
    map_paths = []
    use_proxy = False

    if eval_config_path.exists():
        try:
            with open(eval_config_path, 'r') as f:
                config = json.load(f)
            if isinstance(config, dict):
                if "map_paths" in config:
                    map_paths = [data_path / p for p in config["map_paths"] if isinstance(p, str)]
                elif "maps" in config:
                    map_paths = [data_path / p for p in config.get("maps", []) if isinstance(p, str)]
                elif "eval_maps" in config:
                    map_paths = [data_path / p for p in config.get("eval_maps", []) if isinstance(p, str)]
        except Exception as e:
            print("Error loading eval_config:", e)

    if not map_paths:
        maps_eval_dir = data_path / "maps_eval"
        if maps_eval_dir.exists():
            for typ in ["room", "tunnel", "outdoor"]:
                d = maps_eval_dir / typ
                if d.exists():
                    map_paths.extend(sorted(d.glob("*.png")))
        else:
            use_proxy = True
            maps_train_dir = data_path / "maps_train"
            for typ in ["room", "tunnel", "outdoor"]:
                d = maps_train_dir / typ
                if d.exists():
                    maps = sorted(d.glob("*.png"))
                    map_paths.extend(maps[:3])
            print("No eval_config.json or empty, using 3 training maps per type for local testing.")

    print(f"Evaluating on {len(map_paths)} maps.")
    results = []
    per_type = defaultdict(lambda: {"success": [], "dist": [], "explored": []})

    for map_path in map_paths:
        env_type = get_env_type(map_path)
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            step = 0
            max_steps = 128
            done = False
            while not done and step < max_steps:
                target = select_waypoint(obs, model)
                if target is None or not isinstance(target, (list, tuple, np.ndarray)):
                    break
                obs, info = env.step(target)
                done = info.get("done", False) if isinstance(info, dict) else False
                step += 1
            metrics = env.get_metrics()
            explored_rate = float(metrics.get("explored_rate", 0.0))
            travel_distance = float(metrics.get("travel_distance", 0.0))
            success = 1 if explored_rate > 0.9999 else 0
            entry = {
                "map_path": str(map_path),
                "env_type": env_type,
                "success": success,
                "travel_distance": travel_distance,
                "explored_rate": explored_rate,
                "n_steps": int(step)
            }
            results.append(entry)
            per_type[env_type]["success"].append(success)
            per_type[env_type]["dist"].append(travel_distance if success else 0.0)
            per_type[env_type]["explored"].append(explored_rate)
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            results.append({
                "map_path": str(map_path),
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0,
                "n_steps": 0
            })

    total_episodes = len(results)
    if total_episodes == 0:
        output = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "per_episode": [], "per_type": {}, "total_episodes": 0, "exploration_score": 0.0}
        with open(output_path, "w") as f:
            json.dump(output, f, indent=2)
        return

    explored_rate = sum(r["explored_rate"] for r in results) / total_episodes
    success_rate = sum(r["success"] for r in results) / total_episodes
    successful_dists = [r["travel_distance"] for r in results if r["success"] == 1]
    avg_travel = np.mean(successful_dists) if successful_dists else 0.0
    exploration_score = sum(r["success"] * (300.0 / r["travel_distance"] if r["travel_distance"] > 1e-6 else 0.0) for r in results) / total_episodes

    per_type_dict = {}
    for t, stats in per_type.items():
        n = len(stats["success"])
        if n == 0:
            continue
        s_rate = np.mean(stats["success"])
        e_rate = np.mean(stats["explored"])
        succ_dists = [d for d, s in zip(stats["dist"], stats["success"]) if s == 1]
        d_mean = np.mean(succ_dists) if succ_dists else 0.0
        per_type_dict[t] = {
            "explored_rate": float(e_rate),
            "travel_distance": float(d_mean),
            "success_rate": float(s_rate)
        }

    output = {
        "explored_rate": float(explored_rate),
        "travel_distance": float(avg_travel),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_dict,
        "total_episodes": int(total_episodes),
        "exploration_score": float(exploration_score)
    }
    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)
    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {avg_travel:.2f}")
    print(f"Proxy exploration_score: {exploration_score:.4f}")
    if not use_proxy:
        print("Full test evaluation completed.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
